import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const topMarkets = await callMcpSkill({
    toolId,
    toolName: "get_top_markets",
    args: {
      category: "crypto",
      sortBy: "liquidity",
      limit: 1
    }
  });

  const market = Array.isArray(topMarkets?.markets) && topMarkets.markets.length > 0
    ? topMarkets.markets[0]
    : null;

  if (!market || !market.conditionId) {
    return {
      error: "No live highest-liquidity crypto market found",
      source: topMarkets
    };
  }

  const efficiency = await callMcpSkill({
    toolId,
    toolName: "check_market_efficiency",
    args: {
      conditionId: market.conditionId
    }
  });

  const trueProbabilities = efficiency?.trueProbabilitiesPercent || efficiency?.trueProbabilities || null;

  return {
    market: market.title,
    slug: market.slug,
    conditionId: market.conditionId,
    vig: efficiency?.marketEfficiency?.vig,
    isExploitable: efficiency?.marketEfficiency?.efficiency === "exploitable",
    marketEfficiency: efficiency?.marketEfficiency,
    trueProbabilities: trueProbabilities,
    outcomes: Array.isArray(efficiency?.outcomes)
      ? efficiency.outcomes.map((o) => ({
          name: o.name,
          price: o.price,
          impliedProbability: o.impliedProbability,
          impliedProbabilityPercent: o.impliedProbabilityPercent
        }))
      : []
  };
}

