const POLYMARKET_TOOL_ID = "294100e8-c648-4e5f-a254-95a14b56e398";

export async function main() {
  const topMarkets = await callMcpSkill({
    toolId: POLYMARKET_TOOL_ID,
    toolName: "get_top_markets",
    args: {
      category: "politics",
      sortBy: "volume",
      limit: 1
    }
  });

  const markets = Array.isArray(topMarkets?.markets) ? topMarkets.markets : [];
  const topMarket = markets[0] || null;

  if (!topMarket || !topMarket.conditionId) {
    return {
      missingData: ["topPoliticsMarket", "conditionId"],
      attemptedBranches: ["get_top_markets(category=politics, sortBy=volume, limit=1)"],
      stopReason: "No suitable politics market was returned."
    };
  }

  const whaleFlow = await callMcpSkill({
    toolId: POLYMARKET_TOOL_ID,
    toolName: "analyze_whale_flow",
    args: {
      conditionId: topMarket.conditionId,
      hoursBack: 48
    }
  });

  const flowBySize = whaleFlow?.flowBySize || {};
  const whale = flowBySize.whale || {};
  const small = flowBySize.small || {};

  return {
    market: topMarket.title || topMarket.market || null,
    conditionId: topMarket.conditionId,
    totalTrades: whaleFlow?.totalTrades ?? null,
    whaleNetSentiment: whale?.sentiment ?? null,
    retailNetSentiment: small?.sentiment ?? null,
    divergence: whaleFlow?.divergence ?? null,
    selectedMarket: {
      title: topMarket.title || null,
      url: topMarket.url || null,
      currentPrice: topMarket.currentPrice ?? null,
      volume24h: topMarket.volume24h ?? null
    }
  };
}

