        "get_top_markets(category=politics, sortBy=competitive, limit=25)",
        "pickTopSemanticCandidates(target=near 50/50 politics market with deepest liquidity)"
      ]
    };
  }

  const holders = await callMcpSkill({
    toolId: POLYMARKET_TOOL_ID,
    toolName: "analyze_top_holders",
    args: {
      conditionId: chosen.conditionId,
      deepFetch: true,
      limit: 3,
      outcome: "BOTH"
    }
  });

  const yesWhalesRaw = Array.isArray(holders?.whaleAnalysis?.yesWhales) ? holders.whaleAnalysis.yesWhales : [];
  const noWhalesRaw = Array.isArray(holders?.whaleAnalysis?.noWhales) ? holders.whaleAnalysis.noWhales : [];

  const top3YESWhales = yesWhalesRaw
    .slice()
    .sort((a, b) => (b.positionValue || 0) - (a.positionValue || 0))
    .slice(0, 3)
    .map((h) => ({
      rank: h.rank,
      address: h.address,
      shares: h.shares,
      positionValue: h.positionValue,
      estimatedEntry: h.estimatedEntry,
      convictionScore: h.convictionScore
    }));

  const top3NOWhales = noWhalesRaw
    .slice()
    .sort((a, b) => (b.positionValue || 0) - (a.positionValue || 0))
    .slice(0, 3)
    .map((h) => ({
      rank: h.rank,
      address: h.address,
      shares: h.shares,
      positionValue: h.positionValue,
      estimatedEntry: h.estimatedEntry,
      convictionScore: h.convictionScore
    }));

  const concentration = holders?.marketConcentration || null;
  const smartMoneySignalDirection = holders?.smartMoneySignal?.direction || null;

  return {
    selectedMarket: {
      title: chosen.title,
      conditionId: chosen.conditionId,
      url: chosen.url,
      liquidity: chosen.liquidity,
      currentPrice: chosen.currentPrice,
      distanceTo50: chosen._distanceTo50
    },
    top3YESWhales,
    top3NOWhales,
    smartMoneySignalDirection,
    top5YesPercent: concentration?.top5YesPercent ?? null,
    top5NoPercent: concentration?.top5NoPercent ?? null,
    concentration,
    note: "This plan uses the requested analyze_top_holders tool directly after shortlist-first market selection."
  };
}
